#include <bits/stdc++.h>

using namespace std;

int n, w;
int a[1001], f[10001];
int main() {
	ios::sync_with_stdio(false);
	cin.tie(0);
	cin >> n;
    cin >> w;
	for (int i = 1; i <= n; i++) cin >> a[i];

	f[0] = 0;
	for (int i = 1; i <= w; i++) {
		f[i] = 1e9;
		for (int j = 1; j <= n; j++)
			if (a[j] <= i) f[i] = min (f[i], f[i - a[j]] + 1);
	}
	cout << f[w];
	return 0;
}
